import './App.css';
import {Routes, Route, useNavigate} from 'react-router-dom'
import  Menu  from './Menu';
import  About  from './About'
import { Modal } from 'antd';

function App() {

  const navigation = useNavigate()

  let title = "Men Dasturchiman"
  let name = "Nuriddin"
  let nameTwo = "Alijon"

  const openAbout = () => {
    navigation('about')
  }

  const back = () => {
    navigation(-1)
  }


  return (
  <div className='App'>

    <Menu title='app dan yuborilmoqda' name={name} next={nameTwo} />

    <Routes>
      <Route path='about' element={<About title={title} back={back} name='Nuriddin' />} />
    </Routes>

    <button onClick={openAbout}>Aboutga o'tsin</button>

    <Routes>
      <Route path='/' element={<About title={title}/>}/>
    </Routes>

    {/* <Routes>
      {routes.map((route, index) => (
        <Route 
        key={index}
        path={route.path}
        element={route.element}
        />
      ))}
    </Routes> */}
    <Modal />
  </div>
  );
}

export default App;
